// Array: {4, 1, 2, 1, 2}
// Every number appears EXACTLY TWICE, except one number which appears ONCE
// Find that single number — in O(n) time and O(1) EXTRA space

#include <iostream>
#include <vector>

using namespace std;

int singleNumber(vector<int> &nums)
{
    int result = 0;

    for (int num : nums)
    {
        result ^= num; // XOR everything together
    }

    return result;
}

int main()
{
    vector<int> nums = {4, 1, 2, 1, 2};

    cout << singleNumber(nums) << endl;

    return 0;
}

int countSetBits(int n)
{
    int count = 0;
    while (n > 0)
    {
        count += (n & 1); // check the last bit
        n >>= 1;          // shift right, move to the next bit
    }
    return count;
}

// A power of two has EXACTLY one set bit, giving a neat check:
bool isPowerOfTwo(int n)
{
    return n > 0 && (n & (n - 1)) == 0;
}

